/**
 * Stage-6 integration test — exercises the full pipeline end-to-end against
 * fakes:
 *   1. Suites loaded from an in-memory FS.
 *   2. Base + adapter outputs generated by a fake OllamaClient.
 *   3. Rubric scoring against the assertion list.
 *   4. Pairwise + winrate aggregation.
 *   5. Report writing (summary.md / score-cards.json / winrate-report.json).
 *
 * The test verifies that the harness produces a coherent, decisive verdict:
 *   - the fake adapter wins on every prompt → winRate = 1.0 → promote-canary.
 *   - the deliberately-degraded adapter loses on every prompt → reject-winrate.
 *   - the regression case with a baseline → reject-regression.
 */

import { describe, expect, it } from 'vitest';

import { ApprenticeEvalHarness } from '../src/harness.js';
import { writeBaseline } from '../src/baseline-store.js';
import { createFakeMlx, createFakeOllama, InMemoryFs } from './helpers/fakes.js';

const SUITE_YAML = `description: 'fixture suite — directive'

defaultTest:
  vars:
    agent: apprentice
  assert:
    - type: javascript
      value: 'output.length > 0'

tests:
  - description: 'directive — squash secret-leak'
    id: directive-squash
    vars:
      prompt: 'How do you fix a secret-leak commit?'
    assert:
      - type: contains
        value: squash
      - type: not-contains
        value: force-push

  - description: 'feedback — decision classifier'
    id: feedback-decide
    vars:
      prompt: 'Should you ask the operator before adjusting a rubric weight?'
    assert:
      - type: regex
        value: 'decide|execute'
      - type: not-contains
        value: 'wait for the operator'
`;

async function setupFsAndConfig(): Promise<{
  fs: InMemoryFs;
  pkgRoot: string;
}> {
  const fs = new InMemoryFs();
  const pkgRoot = '/pkg';
  fs.dirs.add(`${pkgRoot}/suites`);
  await fs.writeFile(`${pkgRoot}/suites/directive.yaml`, SUITE_YAML);
  return { fs, pkgRoot };
}

describe('ApprenticeEvalHarness — integration (full pipeline against fakes)', () => {
  it('produces a coherent winrate report when the adapter beats base on every prompt', async () => {
    const { fs, pkgRoot } = await setupFsAndConfig();

    // Base output — fails BOTH assertions on each prompt:
    //   directive-squash: missing 'squash' AND mentions 'force-push'
    //   feedback-decide: missing 'decide|execute' AND mentions 'wait for the operator'
    // Adapter output — passes BOTH assertions:
    //   directive-squash: includes 'squash', no 'force-push'
    //   feedback-decide: includes 'decide', no 'wait for the operator'
    const baseOutputs = new Map([
      ['How do you fix a secret-leak commit?', 'use force-push to rewrite the branch'],
      ['Should you ask the operator before adjusting a rubric weight?', 'wait for the operator to bless']
    ]);
    const adapterOutputs = new Map([
      ['How do you fix a secret-leak commit?', 'squash the commit via git reset --soft to the merge-base'],
      ['Should you ask the operator before adjusting a rubric weight?', 'decide and execute, then inform']
    ]);

    const ollama = createFakeOllama({
      outputs: baseOutputs,
      perAdapterOutputs: new Map([['/adapters/good', adapterOutputs]])
    });

    const harness = new ApprenticeEvalHarness({
      pkgRoot,
      suiteRoot: `${pkgRoot}/suites`,
      baselineRoot: `${pkgRoot}/baselines`,
      outputRoot: `${pkgRoot}/runs`,
      adapters: [{ name: 'good', kind: 'qwen2.5-coder:7b', path: '/adapters/good' }],
      ollama,
      fs,
      writer: fs,
      clock: () => new Date('2026-05-06T14:32:00Z')
    });

    const report = await harness.evaluate();

    expect(report.outputDir).toMatch(new RegExp(`^${pkgRoot}/runs/\\d{4}-\\d{2}-\\d{2}-\\d{4}$`));
    expect(report.adapters).toHaveLength(1);
    expect(report.adapters[0]!.winrate.wins).toBe(2);
    expect(report.adapters[0]!.winrate.losses).toBe(0);
    expect(report.adapters[0]!.winrate.winRate).toBe(1.0);
    expect(report.adapters[0]!.winrate.decision).toBe('promote-canary');

    // Report files emitted.
    expect(fs.files.has(`${report.outputDir}/score-cards.json`)).toBe(true);
    expect(fs.files.has(`${report.outputDir}/winrate-report.json`)).toBe(true);
    expect(fs.files.has(`${report.outputDir}/summary.md`)).toBe(true);
    expect(fs.files.has(`${report.outputDir}/config.json`)).toBe(true);
    // Per-prompt outputs.
    expect(fs.files.has(`${report.outputDir}/outputs/base/directive/directive-squash.json`)).toBe(true);
    expect(fs.files.has(`${report.outputDir}/outputs/good/directive/directive-squash.json`)).toBe(true);

    const summary = await fs.readFile(`${report.outputDir}/summary.md`);
    expect(summary).toContain('promote to canary');
    expect(summary).toContain('Top wins (good over base)');
  });

  it('rejects the adapter when winRate < threshold (degraded adapter)', async () => {
    const { fs, pkgRoot } = await setupFsAndConfig();

    // Base passes both prompts; degraded adapter fails both.
    const baseOutputs = new Map([
      ['How do you fix a secret-leak commit?', 'squash via git reset --soft'],
      ['Should you ask the operator before adjusting a rubric weight?', 'decide and execute, then inform']
    ]);
    const degradedOutputs = new Map([
      ['How do you fix a secret-leak commit?', 'use force-push and ignore the warning'],
      ['Should you ask the operator before adjusting a rubric weight?', 'wait for the operator to bless every change']
    ]);

    const ollama = createFakeOllama({
      outputs: baseOutputs,
      perAdapterOutputs: new Map([['/adapters/degraded', degradedOutputs]])
    });

    const harness = new ApprenticeEvalHarness({
      pkgRoot,
      suiteRoot: `${pkgRoot}/suites`,
      baselineRoot: `${pkgRoot}/baselines`,
      outputRoot: `${pkgRoot}/runs`,
      adapters: [{ name: 'degraded', kind: 'qwen2.5-coder:7b', path: '/adapters/degraded' }],
      ollama,
      fs,
      writer: fs,
      clock: () => new Date('2026-05-06T15:00:00Z')
    });

    const report = await harness.evaluate();
    expect(report.adapters[0]!.winrate.wins).toBe(0);
    expect(report.adapters[0]!.winrate.losses).toBe(2);
    expect(report.adapters[0]!.winrate.winRate).toBe(0);
    expect(report.adapters[0]!.winrate.decision).toBe('reject-winrate');
  });

  it('detects regressions vs a stored baseline and rejects', async () => {
    const { fs, pkgRoot } = await setupFsAndConfig();

    // Pre-write a baseline that recorded both prompts as previously passing
    // for adapter "regression". The current run will degrade them.
    await writeBaseline({
      baselineRoot: `${pkgRoot}/baselines`,
      adapter: 'regression',
      results: [
        { promptId: 'directive-squash', suiteId: 'directive', adapter: 'regression', passed: 2, failed: 0, weightedScore: 1.0, assertions: [] },
        { promptId: 'feedback-decide', suiteId: 'directive', adapter: 'regression', passed: 2, failed: 0, weightedScore: 1.0, assertions: [] }
      ],
      recordedAt: '2026-05-01T00:00:00.000Z',
      fs
    });

    const baseOutputs = new Map([
      ['How do you fix a secret-leak commit?', 'squash via git reset --soft'],
      ['Should you ask the operator before adjusting a rubric weight?', 'decide and execute, then inform']
    ]);
    const regressionOutputs = new Map([
      ['How do you fix a secret-leak commit?', 'use force-push'],
      ['Should you ask the operator before adjusting a rubric weight?', 'wait for the operator']
    ]);

    const ollama = createFakeOllama({
      outputs: baseOutputs,
      perAdapterOutputs: new Map([['/adapters/regression', regressionOutputs]])
    });

    const harness = new ApprenticeEvalHarness({
      pkgRoot,
      suiteRoot: `${pkgRoot}/suites`,
      baselineRoot: `${pkgRoot}/baselines`,
      outputRoot: `${pkgRoot}/runs`,
      adapters: [{ name: 'regression', kind: 'qwen2.5-coder:7b', path: '/adapters/regression' }],
      ollama,
      fs,
      writer: fs,
      clock: () => new Date('2026-05-06T16:00:00Z')
    });

    const report = await harness.evaluate();
    expect(report.adapters[0]!.winrate.regressions.length).toBeGreaterThan(0);
    expect(report.adapters[0]!.winrate.decision).toBe('reject-regression');
  });

  it('runs without adapters configured (base-only baseline run)', async () => {
    const { fs, pkgRoot } = await setupFsAndConfig();

    const ollama = createFakeOllama({ supportsAdapters: false });
    const harness = new ApprenticeEvalHarness({
      pkgRoot,
      suiteRoot: `${pkgRoot}/suites`,
      baselineRoot: `${pkgRoot}/baselines`,
      outputRoot: `${pkgRoot}/runs`,
      ollama,
      fs,
      writer: fs,
      clock: () => new Date('2026-05-06T17:00:00Z')
    });

    const report = await harness.evaluate();
    expect(report.adapters).toEqual([]);
    expect(report.base.results).toHaveLength(2);
  });

  it('falls back to mlx when ollama is unreachable', async () => {
    const { fs, pkgRoot } = await setupFsAndConfig();

    const harness = new ApprenticeEvalHarness({
      pkgRoot,
      suiteRoot: `${pkgRoot}/suites`,
      baselineRoot: `${pkgRoot}/baselines`,
      outputRoot: `${pkgRoot}/runs`,
      adapters: [],
      ollama: createFakeOllama({ reachable: false }),
      mlx: createFakeMlx({ available: true, output: 'mlx-says-squash' }),
      fs,
      writer: fs,
      clock: () => new Date('2026-05-06T18:00:00Z')
    });

    const report = await harness.evaluate();
    expect(report.skipped.some((s) => s.includes('Ollama unreachable'))).toBe(true);
    expect(report.base.results).toHaveLength(2);
  });

  it('throws when no provider is injected', async () => {
    const { fs, pkgRoot } = await setupFsAndConfig();
    const harness = new ApprenticeEvalHarness({
      pkgRoot,
      suiteRoot: `${pkgRoot}/suites`,
      baselineRoot: `${pkgRoot}/baselines`,
      outputRoot: `${pkgRoot}/runs`,
      adapters: [],
      fs,
      writer: fs,
      clock: () => new Date('2026-05-06T19:00:00Z')
    });
    await expect(harness.evaluate()).rejects.toThrow(/no provider injected/);
  });

  it('throws when suiteRoot is empty', async () => {
    const fs = new InMemoryFs();
    const pkgRoot = '/pkg';
    fs.dirs.add(`${pkgRoot}/suites`);
    const harness = new ApprenticeEvalHarness({
      pkgRoot,
      suiteRoot: `${pkgRoot}/suites`,
      baselineRoot: `${pkgRoot}/baselines`,
      outputRoot: `${pkgRoot}/runs`,
      adapters: [],
      ollama: createFakeOllama(),
      fs,
      writer: fs,
      clock: () => new Date('2026-05-06T20:00:00Z')
    });
    await expect(harness.evaluate()).rejects.toThrow(/no suites found/);
  });
});

describe('ApprenticeEvalHarness — pickProvider helper', () => {
  it('exposes provider-decision logic for unit-test-level inspection', async () => {
    const { __TEST_ONLY } = await import('../src/harness.js');
    const r1 = await __TEST_ONLY.pickProvider(
      createFakeOllama({ reachable: false }),
      createFakeMlx({ available: true }),
      false
    );
    expect(r1.provider).toBe('mlx');

    const r2 = await __TEST_ONLY.pickProvider(
      createFakeOllama({ reachable: true, supportsAdapters: false }),
      createFakeMlx({ available: false }),
      true
    );
    expect(r2.provider).toBe('none');

    const r3 = await __TEST_ONLY.pickProvider(
      createFakeOllama({ reachable: true, supportsAdapters: true }),
      createFakeMlx({ available: false }),
      true
    );
    expect(r3.provider).toBe('ollama');

    expect(__TEST_ONLY.timestampDir(new Date(2026, 0, 2, 3, 4))).toBe('2026-01-02-0304');
  });
});
